  `gait_feature_confirmed` varchar(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT '0' COMMENT 'notcollected，confirmed，notbound',
  `image` longblob NULL COMMENT '证件照',
  `collect_start_time` datetime(0) NULL DEFAULT NULL COMMENT '采集开始时间',
  `collect_end_time` datetime(0) NULL DEFAULT NULL COMMENT '采集结束时间',
  `camera_id` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '摄像头id，逗号分割',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `mts_card_no`(`mts_card_no`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_onboard_date`(`onboard_date`) USING BTREE,
  INDEX `idx_certificate_expire`(`certificate_expire_date`) USING BTREE,
  INDEX `idx_platform_no`(`platform_no`) USING BTREE,
  INDEX `idx_gait_confirmed`(`gait_feature_confirmed`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 27 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_bin ROW_FORMAT = Dynamic;

