  `login_time` datetime(0) NULL DEFAULT NULL COMMENT '访问时间',
  `platform_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '钻井平台编号',
